/**
 * Webhooks service client.
 *
 * Provides WebhooksService for managing webhook endpoints via the
 * Infrared API (CRUD operations) and verifying webhook signatures
 * using the Standard Webhooks HMAC-SHA256 scheme.
 *
 * Signature verification uses `crypto.subtle` for isomorphic
 * compatibility (browser, Node, Cloudflare Workers). Timing-safe
 * comparison uses the double-HMAC pattern to avoid timing attacks
 * without relying on `crypto.timingSafeEqual`.
 */

import type { AuthResolver } from '../auth'
import { HttpClient } from '../http'
import type { Logger } from '../logger'
import {
  type WebhookEndpoint,
  WebhookError,
  WebhookNotFoundError,
  WebhookRegistrationError,
  webhookEndpointFromResponse,
} from './types'

export interface WebhooksServiceConfig {
  /** Auth header resolver — supports apiKey + JWT (token / getToken). */
  getAuthHeaders: AuthResolver
  baseUrl: string
  logger: Logger
  /** Request timeout in milliseconds */
  timeout?: number
  /** Maximum number of retries for retryable errors. Default: 2 */
  maxRetries?: number
}

/**
 * Interface for dependency injection and testing.
 */
export interface IWebhooksService {
  register(url: string, type: string, ip?: string): Promise<WebhookEndpoint>
  list(): Promise<WebhookEndpoint[]>
  get(endpointId: string): Promise<WebhookEndpoint>
  delete(endpointId: string): Promise<void>
  verifySignature(
    payloadBody: Uint8Array | string,
    headers: Record<string, string>,
    secret: string,
    tolerance?: number,
  ): Promise<boolean>
}

/**
 * Service for managing webhook endpoints and verifying signatures.
 *
 * CRUD operations (register, list, get, delete) communicate with the
 * Infrared webhooks API. Signature verification uses HMAC-SHA256 via
 * `crypto.subtle` with the Standard Webhooks format.
 */
export class WebhooksService implements IWebhooksService {
  private httpClient: HttpClient
  private logger: Logger

  constructor(config: WebhooksServiceConfig) {
    this.httpClient = new HttpClient({
      getAuthHeaders: config.getAuthHeaders,
      baseUrl: config.baseUrl,
      logger: config.logger,
      timeout: config.timeout,
      maxRetries: config.maxRetries,
    })
    this.logger = config.logger
  }

  // -- CRUD methods ---------------------------------------------------------

  /**
   * Register a new webhook endpoint.
   *
   * @param url - The URL to receive webhook events.
   * @param type - Endpoint type ("production" or "development").
   * @param ip - Optional IP address filter.
   * @returns The newly created endpoint.
   * @throws WebhookRegistrationError if the request fails.
   */
  async register(url: string, type: string, ip?: string): Promise<WebhookEndpoint> {
    const payload: Record<string, string> = { url, type }
    if (ip !== undefined) {
      payload.ip = ip
    }

    this.logger.debug(`POST /webhooks (url=${url}, type=${type})`)

    try {
      const data = await this.httpClient.post<Record<string, unknown>>('/webhooks', payload, {
        serializeNames: false,
      })
      return webhookEndpointFromResponse(data)
    } catch (error) {
      throw new WebhookRegistrationError(
        `Failed to register webhook: ${error instanceof Error ? error.message : String(error)}`,
      )
    }
  }

  /**
   * List all webhook endpoints.
   *
   * @returns All registered endpoints.
   * @throws WebhookError if the request fails.
   */
  async list(): Promise<WebhookEndpoint[]> {
    this.logger.debug('GET /webhooks')

    try {
      const data = await this.httpClient.get<Record<string, unknown>[]>('/webhooks')
      return data.map(webhookEndpointFromResponse)
    } catch (error) {
      throw new WebhookError(
        `Failed to list webhooks: ${error instanceof Error ? error.message : String(error)}`,
      )
    }
  }

  /**
   * Get a specific webhook endpoint by ID.
   *
   * @param endpointId - The ID of the endpoint to retrieve.
   * @returns The requested endpoint.
   * @throws WebhookNotFoundError if the endpoint is not found (404).
   * @throws WebhookError if the request fails for other reasons.
   */
  async get(endpointId: string): Promise<WebhookEndpoint> {
    this.logger.debug(`GET /webhooks/${endpointId}`)

    try {
      const data = await this.httpClient.get<Record<string, unknown>>(`/webhooks/${endpointId}`)
      return webhookEndpointFromResponse(data)
    } catch (error) {
      const msg = error instanceof Error ? error.message : String(error)
      if (isHttpStatus(msg, 404)) {
        throw new WebhookNotFoundError(`Webhook endpoint not found: ${endpointId}`)
      }
      throw new WebhookError(`Failed to get webhook ${endpointId}: ${msg}`)
    }
  }

  /**
   * Delete a webhook endpoint by ID.
   *
   * @param endpointId - The ID of the endpoint to delete.
   * @throws WebhookNotFoundError if the endpoint is not found (404).
   * @throws WebhookError if the request fails for other reasons.
   */
  async delete(endpointId: string): Promise<void> {
    this.logger.debug(`DELETE /webhooks/${endpointId}`)

    try {
      await this.httpClient.delete(`/webhooks/${endpointId}`)
    } catch (error) {
      const msg = error instanceof Error ? error.message : String(error)
      if (isHttpStatus(msg, 404)) {
        throw new WebhookNotFoundError(`Webhook endpoint not found: ${endpointId}`)
      }
      throw new WebhookError(`Failed to delete webhook ${endpointId}: ${msg}`)
    }
  }

  // -- Signature verification -----------------------------------------------

  /**
   * Verify a Standard Webhooks HMAC-SHA256 signature.
   *
   * Validates that the signature in the `webhook-signature` header matches
   * the expected HMAC for the given payload, and that the timestamp is
   * within the tolerance window (replay protection).
   *
   * Uses `crypto.subtle` for HMAC computation (isomorphic: browser, Node,
   * CF Workers) and a double-HMAC pattern for timing-safe comparison
   * (no dependency on `crypto.timingSafeEqual`).
   *
   * @param payloadBody - The raw request body (bytes or string).
   * @param headers - Request headers containing `webhook-id`, `webhook-timestamp`, and `webhook-signature`.
   * @param secret - The webhook secret (`"whsec_"` prefixed, base64-encoded).
   * @param tolerance - Maximum age of the timestamp in seconds (default 300). Set to 0 to disable replay protection.
   * @returns `true` if the signature is valid and the timestamp is within tolerance.
   */
  async verifySignature(
    payloadBody: Uint8Array | string,
    headers: Record<string, string>,
    secret: string,
    tolerance = 300,
  ): Promise<boolean> {
    // Normalize header keys to lowercase for case-insensitive lookup
    const normalizedHeaders: Record<string, string> = {}
    for (const [key, value] of Object.entries(headers)) {
      normalizedHeaders[key.toLowerCase()] = value
    }

    const webhookId = normalizedHeaders['webhook-id']
    const webhookTimestamp = normalizedHeaders['webhook-timestamp']
    const webhookSignature = normalizedHeaders['webhook-signature']

    if (!webhookId || !webhookTimestamp || !webhookSignature) {
      return false
    }

    // Replay protection: validate timestamp within tolerance
    if (tolerance > 0) {
      const ts = Number.parseInt(webhookTimestamp, 10)
      if (Number.isNaN(ts)) {
        return false
      }

      const now = Math.floor(Date.now() / 1000)
      if (Math.abs(now - ts) > tolerance) {
        return false
      }
    }

    // Decode secret: strip "whsec_" prefix, base64-decode
    const rawSecret = secret.startsWith('whsec_') ? secret.slice(6) : secret
    let keyBytes: Uint8Array
    try {
      keyBytes = base64Decode(rawSecret)
    } catch {
      return false
    }

    // Compute expected signature
    let bodyBytes: Uint8Array
    if (typeof payloadBody === 'string') {
      bodyBytes = new TextEncoder().encode(payloadBody)
    } else {
      bodyBytes = payloadBody
    }

    const prefixBytes = new TextEncoder().encode(`${webhookId}.${webhookTimestamp}.`)
    const signedContent = new Uint8Array(prefixBytes.length + bodyBytes.length)
    signedContent.set(prefixBytes, 0)
    signedContent.set(bodyBytes, prefixBytes.length)

    // Import HMAC key
    let cryptoKey: CryptoKey
    try {
      cryptoKey = await crypto.subtle.importKey(
        'raw',
        keyBytes.buffer as ArrayBuffer,
        { name: 'HMAC', hash: 'SHA-256' },
        false,
        ['sign'],
      )
    } catch {
      return false
    }

    // Sign
    const signatureBuffer = await crypto.subtle.sign('HMAC', cryptoKey, signedContent)
    const expectedSig = base64Encode(new Uint8Array(signatureBuffer))

    // The webhook-signature header may contain multiple signatures
    // separated by spaces, each prefixed with "v1,"
    for (const sigEntry of webhookSignature.split(' ')) {
      const commaIdx = sigEntry.indexOf(',')
      if (commaIdx === -1) {
        continue
      }
      const version = sigEntry.slice(0, commaIdx)
      const sigValue = sigEntry.slice(commaIdx + 1)
      if (version === 'v1') {
        // Timing-safe comparison via double-HMAC pattern:
        // HMAC(random_key, a) === HMAC(random_key, b) iff a === b
        // This avoids timing leaks from string comparison
        const isEqual = await timingSafeEqual(expectedSig, sigValue)
        if (isEqual) {
          return true
        }
      }
    }

    return false
  }
}

// ---------------------------------------------------------------------------
// Internal helpers
// ---------------------------------------------------------------------------

/**
 * Check if an error message matches a specific HTTP status code.
 *
 * HttpClient throws errors in the format "HTTP {status}: {body}",
 * so we match against that prefix pattern.
 */
function isHttpStatus(message: string, status: number): boolean {
  return message.startsWith(`HTTP ${status}:`)
}

/**
 * Base64 decode a string to Uint8Array.
 * Isomorphic: uses atob (available in all target environments).
 */
function base64Decode(encoded: string): Uint8Array {
  const binaryString = atob(encoded)
  const bytes = new Uint8Array(binaryString.length)
  for (let i = 0; i < binaryString.length; i++) {
    bytes[i] = binaryString.charCodeAt(i)
  }
  return bytes
}

/**
 * Base64 encode a Uint8Array to string.
 * Isomorphic: uses btoa (available in all target environments).
 */
function base64Encode(bytes: Uint8Array): string {
  const CHUNK_SIZE = 8192
  const chunks: string[] = []
  for (let offset = 0; offset < bytes.length; offset += CHUNK_SIZE) {
    const slice = bytes.subarray(offset, Math.min(offset + CHUNK_SIZE, bytes.length))
    chunks.push(String.fromCharCode.apply(null, slice as unknown as number[]))
  }
  return btoa(chunks.join(''))
}

/**
 * Timing-safe string comparison using the double-HMAC pattern.
 *
 * Instead of comparing strings directly (which leaks timing information),
 * we compute HMAC(randomKey, a) and HMAC(randomKey, b) and compare the
 * resulting digests. Since HMAC output is uniformly distributed, any
 * difference in inputs produces completely different outputs, making
 * byte-by-byte comparison safe.
 *
 * This pattern works in all environments without `crypto.timingSafeEqual`.
 */
async function timingSafeEqual(a: string, b: string): Promise<boolean> {
  // Generate a random key for the double-HMAC comparison
  const randomKeyBytes = new Uint8Array(32)
  crypto.getRandomValues(randomKeyBytes)

  const key = await crypto.subtle.importKey(
    'raw',
    randomKeyBytes.buffer as ArrayBuffer,
    { name: 'HMAC', hash: 'SHA-256' },
    false,
    ['sign'],
  )

  const encoder = new TextEncoder()
  const [hmacA, hmacB] = await Promise.all([
    crypto.subtle.sign('HMAC', key, encoder.encode(a)),
    crypto.subtle.sign('HMAC', key, encoder.encode(b)),
  ])

  // Compare the HMAC digests byte-by-byte
  // This is safe because HMAC outputs are uniformly distributed
  const viewA = new Uint8Array(hmacA)
  const viewB = new Uint8Array(hmacB)

  if (viewA.length !== viewB.length) {
    return false
  }

  let diff = 0
  for (let i = 0; i < viewA.length; i++) {
    diff |= viewA[i] ^ viewB[i]
  }

  return diff === 0
}
